urlset:
{%- for entry in entries %}
  {%- if not entry.permalink is containing("/tags/")
      and not entry.permalink is containing("/blog/archive/")
      and not entry.permalink is containing("/blog/page/1/") %}

    {{ entry.permalink | safe }}
    {%- if entry.updated %}
    {{ entry.updated }}
    {%- endif %}

  {%- endif %}
{%- endfor %}
